19	const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
20	
21	const componentBasePremium = (items: Item[]): number => {
22	  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
23	  const counts = new Map<string, number>();
24	  for (const c of components) {
25	    counts.set(c.type, (counts.get(c.type) ?? 0) + 1);
26	  }
27	  let total = 0;
28	  for (const count of counts.values()) {
29	    const blocks = Math.floor(count / BLOCK_SIZE);
30	    const leftover = count - blocks * BLOCK_SIZE;
31	    total += blocks * BLOCK_PREMIUM + leftover * 25;
32	  }
33	  return total;
34	};
35	
36	const quotePremium = (items: Item[]): number => {
37	  const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
38	  const mainTotal = mainItems.reduce((sum, item) => sum + basePremium(item), 0);
39	  return mainTotal + componentBasePremium(items) + PROCESSING_FEE;
40	};
